-- Resetear contadores CRM (presupuesto, factura, reserva, anulacion)
-- NO resetear TPV ni liquidacion ni cupon
UPDATE document_counters SET current_number = 0 
WHERE document_type IN ('presupuesto', 'factura', 'reserva', 'anulacion');

-- Limpiar reservation_operational huérfanos (sin reserva vinculada)
DELETE FROM reservation_operational WHERE reservation_id NOT IN (SELECT id FROM reservations);

-- Limpiar transacciones que no son de TPV y quedaron huérfanas
DELETE FROM transactions WHERE tpvSaleId IS NULL;

